module top_module(
    input clk_inv,
    input rst_n,
    input enable,
    output reg VPWR,
    output reg VGND
);always @(posedge clk_inv or negedge rst_n) begin
    if (!rst_n) begin
        VPWR <= 0;
        VGND <= 0;
    end else if (enable) begin
        VPWR <= 1;
        VGND <= 0;
    end else begin
        VPWR <= 0;
        VGND <= 0;
    end
end

endmodule
